8568   auto IsNegationOf = [&](const Value *X, const Value *Y) {
8569     if (!match(X, m_Neg(m_Specific(Y))))
8570       return false;
8571 
8572     auto *BO = cast<BinaryOperator>(X);
8573     if (NeedNSW && !BO->hasNoSignedWrap())
