8575 
8576     auto *Zero = cast<Constant>(BO->getOperand(0));
8577     if (!AllowPoison && !Zero->isNullValue())
8578       return false;
8579 
8580     return true;
8581   };
8582 
8583   // X = -Y or Y = -X
8584   if (IsNegationOf(X, Y) || IsNegationOf(Y, X))
8585     return true;
8586 
8587   // X = sub (A, B), Y = sub (B, A) || X = sub nsw (A, B), Y = sub nsw (B, A)
