9467   // constant.
9468   const APInt *Unused;
9469   if (L0 == R0 && (match(L1, m_APInt(Unused)) || match(R1, m_APInt(Unused)))) {
9470     // Potential TODO: We could also further use the constant range of L0/R0 to
9471     // further constraint the constant ranges. At the moment this leads to
9472     // several regressions related to not transforming `multi_use(A + C0) eq/ne
9473     // C1` (see discussion: D58633).
9474     ConstantRange LCR = computeConstantRange(
9475         L1, ICmpInst::isSigned(LPred), /* UseInstrInfo=*/true, /*AC=*/nullptr,
9476         /*CxtI=*/nullptr, /*DT=*/nullptr, MaxAnalysisRecursionDepth - 1);
9477     ConstantRange RCR = computeConstantRange(
9478         R1, ICmpInst::isSigned(RPred), /* UseInstrInfo=*/true, /*AC=*/nullptr,
9479         /*CxtI=*/nullptr, /*DT=*/nullptr, MaxAnalysisRecursionDepth - 1);
9480     // Even if L1/R1 are not both constant, we can still sometimes deduce
9481     // relationship from a single constant. For example X u> Y implies X != 0.
9482     if (auto R = isImpliedCondCommonOperandWithCR(LPred, LCR, RPred, RCR))
9483       return R;
9484     // If both L1/R1 were exact constant ranges and we didn't get anything
9485     // here, we won't be able to deduce this.
9486     if (match(L1, m_APInt(Unused)) && match(R1, m_APInt(Unused)))
9487       return std::nullopt;
9488   }
9489 
9490   // Can we infer anything when the two compares have matching operands?
9491   if (L0 == R0 && L1 == R1)
9492     return isImpliedCondMatchingOperands(LPred, RPred);
9493 
9494   // It only really makes sense in the context of signed comparison for "X - Y
9495   // must be positive if X >= Y and no overflow".
9496   // Take SGT as an example:  L0:x > L1:y and C >= 0
9497   //                      ==> R0:(x -nsw y) < R1:(-C) is false
9498   if ((CmpPredicate::getMatching(LPred, ICmpInst::ICMP_SGT) ||
9499        CmpPredicate::getMatching(LPred, ICmpInst::ICMP_SGE)) &&
9500       match(R0, m_NSWSub(m_Specific(L0), m_Specific(L1)))) {
9501     if (match(R1, m_NonPositive()) &&
9502         isImpliedCondMatchingOperands(LPred, RPred) == false)
9503       return false;
9504   }
9505 
9506   // Take SLT as an example:  L0:x < L1:y and C <= 0
9507   //                      ==> R0:(x -nsw y) < R1:(-C) is true
9508   if ((CmpPredicate::getMatching(LPred, ICmpInst::ICMP_SLT) ||
9509        CmpPredicate::getMatching(LPred, ICmpInst::ICMP_SLE)) &&
9510       match(R0, m_NSWSub(m_Specific(L0), m_Specific(L1)))) {
9511     if (match(R1, m_NonNegative()) &&
9512         isImpliedCondMatchingOperands(LPred, RPred) == true)
9513       return true;
9514   }
9515 
9516   // L0 = R0 = L1 + R1, L0 >=u L1 implies R0 >=u R1, L0 <u L1 implies R0 <u R1
9517   if (L0 == R0 &&
9518       (LPred == ICmpInst::ICMP_ULT || LPred == ICmpInst::ICMP_UGE) &&
9519       (RPred == ICmpInst::ICMP_ULT || RPred == ICmpInst::ICMP_UGE) &&
9520       match(L0, m_c_Add(m_Specific(L1), m_Specific(R1))))
9521     return CmpPredicate::getMatching(LPred, RPred).has_value();
9522 
9523   if (auto P = CmpPredicate::getMatching(LPred, RPred))
9524     return isImpliedCondOperands(*P, L0, L1, R0, R1);
9525 
9526   return std::nullopt;
9527 }
